
(function(global){

function jsPDF(){
  this.internal = {};

  this.text = function(text, x, y){
    console.log("PDF TEXT:", text);
  };

  this.output = function(){
    return new Blob(["COMET OS OFFLINE PDF"], {type:"application/pdf"});
  };

  this.save = function(name){
    console.log("Saving PDF:", name);
  };
}

global.jspdf = {
  jsPDF: jsPDF
};

})(typeof window !== "undefined" ? window : this);
